// ========================================
// CÓDIGO CORRIGIDO PARA O NÓ "⚙️ Decidir Ação"
// ========================================

// 1. PEGA OS DADOS DA PLANILHA (Edit Fields)
// Agora busca do nó específico ao invés de usar índice
const planilhaItems = $('Edit Fields').all();

// 2. PEGA OS DADOS DO BANCO (Supabase)
// Busca do nó de busca do Supabase
const supabaseItems = $('🔍 Buscar Todos Registros Supabase2').all();

// 3. VALIDAÇÃO: Garante que recebemos os dados
if (!planilhaItems || planilhaItems.length === 0) {
  throw new Error('❌ Nenhum dado da planilha recebido! Verifique a conexão com "Edit Fields"');
}

console.log(`✅ Dados recebidos:`);
console.log(`   - Planilha: ${planilhaItems.length} registros`);
console.log(`   - Supabase: ${supabaseItems.length} registros`);

// 4. CRIA MAPA DO BANCO PARA BUSCA RÁPIDA
const bancoMap = {};
for (const item of supabaseItems) {
  if (item.json && item.json.chapa) {
    const chapa = String(item.json.chapa).trim();
    bancoMap[chapa] = item.json;
  }
}

console.log(`📊 Mapa do banco criado com ${Object.keys(bancoMap).length} chapas`);

// 5. CONTADORES PARA LOG
let insertsCount = 0;
let updatesCount = 0;
let skipsCount = 0;

// 6. COMPARA E DECIDE AÇÃO PARA CADA ITEM DA PLANILHA
const resultado = planilhaItems.map((pItem, index) => {
  const row = pItem.json;

  // Valida se tem chapa
  if (!row.chapa) {
    console.log(`⚠️ Linha ${index + 1}: Sem chapa, pulando...`);
    skipsCount++;
    return { json: { ...row, operation: 'skip', motivo: 'sem_chapa' } };
  }

  const chapa = String(row.chapa).trim();
  const dadoBanco = bancoMap[chapa];

  // SE NÃO EXISTE NO BANCO → INSERT
  if (!dadoBanco) {
    insertsCount++;
    return { json: { ...row, operation: 'insert' } };
  }

  // SE EXISTE NO BANCO → VERIFICA SE TEM MUDANÇAS
  let hasChanges = false;
  const ignore = ['id', 'created_at', 'updated_at', 'operation', 'motivo'];
  const changedFields = [];

  for (const key of Object.keys(row)) {
    if (ignore.includes(key)) continue;

    const valorPlanilha = String(row[key] || '').trim();
    const valorBanco = String(dadoBanco[key] || '').trim();

    if (valorPlanilha !== valorBanco) {
      hasChanges = true;
      changedFields.push(key);
    }
  }

  if (hasChanges) {
    updatesCount++;
    return { 
      json: { 
        ...row, 
        operation: 'update',
        id: dadoBanco.id, // Adiciona o ID do banco para o UPDATE
        campos_alterados: changedFields.join(', ')
      } 
    };
  } else {
    skipsCount++;
    return { json: { ...row, operation: 'skip', motivo: 'sem_alteracoes' } };
  }
});

// 7. LOG FINAL COM ESTATÍSTICAS
console.log(`\n📊 RESULTADO DA ANÁLISE:`);
console.log(`   ✅ Inserts: ${insertsCount}`);
console.log(`   🔄 Updates: ${updatesCount}`);
console.log(`   ⏭️  Skips: ${skipsCount}`);
console.log(`   📦 Total: ${resultado.length}`);

// 8. RETORNA TODOS OS ITENS COM A OPERAÇÃO DEFINIDA
return resultado;

